"""
mkt-original | hosea | ch13–14 | 25 verses
run: python3 scripts/zc-original-hosea-13-14.py

Key interpretation decisions:
- 13:14: Rendered as rhetorical questions ("Shall I ransom … Shall I redeem …")
  consistent with the MT context of divine withdrawal; Paul's 1 Cor 15:55 use is noted.
  The LXX read as declarative promises — both readings are flagged.
- 13:4: moshia' (savior/deliverer) tied to the Joshua/Jesus root; exclusivity claim.
- 14:4: nidabah (freely/voluntarily) for divine love — same root as freewill offering.
- 14:5: tal (dew) as divine sustaining gift — deliberate contrast with 13:3 where Israel's
  love is the "early dew" that vanishes.
- 14:8: YHWH compared to a "green cypress" — rare botanical metaphor; text is difficult.
"""

import json, pathlib, sys

ROOT = pathlib.Path(__file__).resolve().parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HOSEA = {
  "13": {
    "1": "<p><span class='term'>When Ephraim spoke</span> — the verse opens with a participial construction recalling a past era when Ephraim held authority. The Hebrew <em>nasa'</em> (lifted up, trembled) gives the sense of nations shuddering at Ephraim's word. The contrast with the following line is sharp: greatness led to apostasy. <em>asham ba-ba'al</em> — he incurred guilt through Baal. <em>Asham</em> (guilt, be guilty) is the root of the guilt-offering (<em>asham</em>); using it here frames Israel's apostasy as a cultic debt that must be satisfied.</p>",
    "2": "<p><span class='term'>They keep sinning</span> — <em>yasafu laḥeto</em>, a Qal perfect with consecutive force; the sins compound. <em>masukit</em> (molten images, cast metal) vs. <em>pesilim</em> (carved idols) — both terms appear; comprehensive coverage of the idol industry. The phrase <em>zovḥei adam 'agalim yishaqun</em> is cryptic: most read 'those who sacrifice men [or: to men?] kiss calves.' <em>Nashaq</em> (kiss) was a cultic act of veneration (1 Kgs 19:18; Ps 2:12). The calf-kiss completes the apostasy tableau from v1.</p>",
    "3": "<p><span class='term'>Morning mist / early dew</span> — two paired similes for impermanence: <em>anan-boqer</em> (morning cloud) and <em>tal mashkim holekh</em> (dew that goes early). The same pairing appears in 6:4 to describe Israel's covenant loyalty (<em>ḥesed</em>). Here the poet turns the accusation back: as you said of your love, so now I say of you. Two more images follow: <em>motz</em> (chaff) driven from threshing floor and <em>'ashan</em> (smoke) from a window — all emphasize rapid, total disappearance. Four images of vanishing in one verse: the rhetoric of divine inevitability.</p>",
    "4": "<p><span class='term'>I am the LORD your God from Egypt</span> — the covenant formula in its exodus form, echoing Exod 20:2. <em>me'erets mitsrayim</em> (from the land of Egypt) anchors identity in redemptive history. The exclusivity claim follows: <em>elohim zulati lo teda'</em> — you shall know no god except me. The key term is <em>moshia'</em> (savior, deliverer) in the final clause: <em>u-moshi'a 'ayin bilti</em> — there is no savior except/apart from me. <em>Moshia'</em> shares the root <em>y-sh-'</em> with Joshua (<em>Yehoshua</em>) and Jesus (<em>Yeshua</em>); the noun denotes active, effective rescue. The claim is absolute: no foreign patron-deity holds this role.</p>",
    "5": "<p><span class='term'>I knew you in the wilderness</span> — <em>da'ati</em> (I knew) with the covenant sense of <em>yada'</em>: relational, elective knowledge (cf. Amos 3:2 'you only have I known'). <em>be'erets talmaveth</em> — in a land of deep drought (or deadly drought; <em>tsalmaveth</em> lit. 'shadow of death'). The wilderness period was YHWH's provision against all natural odds; knowing Israel there was an act of committed care.</p>",
    "6": "<p><span class='term'>When I fed them, they were satisfied</span> — <em>kira'otam vayisbe'u</em>: satisfaction led to pride. The verb sequence tracks the covenant-curse dynamic: satiation (<em>saba'</em>) → pride (<em>rum lev</em>, heart lifted) → forgetting (<em>shakehu</em>, they forgot me). This is the Deuteronomic warning fulfilled (Deut 8:11-14): beware lest you eat and are satisfied and your heart is lifted up and you forget the LORD. Hosea treats the wilderness as the formative period of covenant fidelity; sedentary abundance broke it.</p>",
    "7": "<p><span class='term'>I will be like a lion to them</span> — YHWH shifts from shepherd/lover to predator. Three animals: <em>keshav</em> (lion), <em>namer</em> (leopard), and the bear of v8. The lion imagery is common for divine wrath (Amos 1:2; Isa 31:4); the leopard (<em>namer</em>) is notable for speed and stealth — <em>al derekh asher</em> (on the road to Assyria), the exile route itself becomes the ambush site. The reversal of Exodus: instead of leading them out of the wilderness, YHWH meets them like a predator on the return road.</p>",
    "8": "<p><span class='term'>Like a bear robbed of her cubs</span> — <em>dov shakkul</em> (a bereaved bear) was proverbially ferocious (2 Sam 17:8; Prov 17:12). <em>va'eqra' seghor libam</em> — I will tear open the enclosure of their heart (or: the covering over their heart). <em>Seghor</em> can mean enclosure, cage, or the chest cavity. The graphic imagery continues: <em>ve'okhalem sham ka-laviv</em> — I will devour them there like a lion. The accumulation of predator images (lion → leopard → bear → lion again) is a rhetorical intensification: no escape from divine judgment.</p>",
    "9": "<p><span class='term'>You are destroyed, Israel</span> — <em>shiḥetekhah Yisra'el</em>: the second-person address is stark. The rest of the verse is a crux: <em>ki vi be'ezrekhah</em>. Most read: 'for you are against me [YHWH], your only help.' The implied contrast is total: the one being who could help is now the one bringing ruin. The RSV/ESV read 'your help is in me alone' as the implied positive; the context of judgment makes the negative reading ('who is against you') equally possible. The MKT renders the destructive irony: your only rescuer is now the source of destruction.</p>",
    "10": "<p><span class='term'>Where is your king now</span> — the taunt formula <em>ehi</em> (where is…?) mocks the institutions Israel trusted. <em>malkekha</em> (your king) and <em>shopetekha</em> (your judges) are called into question: <em>she-yoshi'akha bekhol arekhah</em> — who might save you in all your cities. <em>Yoshi'akha</em> is the Hiphil of <em>y-sh-'</em> again — the political leaders offered the same salvation that only YHWH can give. The irony: they demanded a king (1 Sam 8); now that king is exposed as helpless. <em>va'omar</em> (and I said) — divine permission is behind the kingship that now fails them.</p>",
    "11": "<p><span class='term'>I gave you a king in my anger</span> — <em>Eten lekha melekh be'api</span> — the Saul tradition (1 Sam 8-12) stands in the background; the divine concession to monarchy is recast as anger. <em>va'eqqaḥ be'evrati</em> (I took away in my wrath) — both giving and taking are expressions of divine judgment. The king is simultaneously gift and curse; the monarchy contains within it the seeds of its own termination. This verse anchors the political theology: human kingship is inherently unstable because it displaced YHWH's direct rule.</p>",
    "12": "<p><span class='term'>Ephraim's iniquity is bound up</span> — <em>tsarur 'avon Ephrayim</em>: the guilt is stored, preserved, not forgotten. <em>tsarur</em> (bound, tied up) suggests a sealed bundle kept for later reckoning (cf. Job 14:17 'my transgression is sealed up in a bag'). <em>tsefunah ḥatato</em> — his sin is stored/hidden. The two verbs form a hendiadys of preserved judgment: nothing has been discharged, all is held in reserve. The image anticipates the birth imagery of v13: all this stored guilt will now force its way out.</p>",
    "13": "<p><span class='term'>Birth pangs come upon him</span> — <em>ḥevlei yoledah yavo'u lo</em>: labor contractions arrive. But then the devastating twist: <em>hu' ben lo' ḥakham ki-'et lo' ya'amod</em> — he is a son without wisdom, for at the proper time he does not present himself at the mouth of the womb. <em>Misbar banim</em> — the mouth/opening of the womb. The child refuses to be born at the crisis moment. The image of the reluctant child-in-birth is a metaphor for Israel refusing the turn (<em>shuv</em>) that the pangs of judgment are designed to produce. Birth pangs that could lead to new life instead lead to suffocation if the child will not come.</p>",
    "14": "<p><span class='term'>Shall I ransom them from Sheol</span> — <em>miyyad she'ol efdemem</em> and <em>mimmavet ag'alem</em>: the key crux. The Hebrew verbs are Qal imperfects: <em>efdeh</em> (I will ransom / shall I ransom?) and <em>eg'al</em> (I will redeem / shall I redeem?). In context (vv1-13 building toward judgment), the MT points toward rhetorical questions with a negative answer: 'Compassion is hidden from my eyes' (<em>niḥam yissater me'einai</em>) is the clincher — a refusal of relenting. However, Paul's citation in 1 Cor 15:55 ('Where, O death, is your sting? Where, O Sheol, is your victory?') uses the LXX version, which renders these as boasts/taunts directed at death rather than divine questions. The LXX <em>pou</em> (where?) turns the Hebrew interrogatives into triumphant challenges. <em>Dever</em> (plague) and <em>qotev</em> (pestilence) are addressed as death's weapons. The ambiguity is textually significant: the same words that in the MT context convey divine withdrawal become, in Paul's eschatological reading, the language of resurrection victory. Both readings arise legitimately from the consonantal text.</p>",
    "15": "<p><span class='term'>Though he flourishes among his brothers</span> — <em>ben yafri' ben ahim</em>: the wordplay on Ephraim (from <em>parah</em>, to be fruitful). Even in fruitfulness, doom comes: <em>yavo' qadim ruaḥ YHWH</em> — the east wind (sirocco) of YHWH comes. <em>Ruaḥ qadim</em> (east wind) is the desert wind from the wilderness — the same direction as Assyria. It will dry up the spring (<em>maqor</em>) and the fountain (<em>ma'yan</em>). The spring imagery inverts the dew of 14:5 (coming chapter): before the restoration is the devastating drought. <em>Hu' yishsasseh otsar kol-keli ḥemdah</em> — it will plunder the treasury of every precious vessel. Military conquest follows agricultural ruin.</p>",
    "16": "<p><span class='term'>Samaria shall bear her guilt</span> — <span class='term'><em>te'sham Shomron</em></span>: the capital city as metonym for the entire northern kingdom. <em>ki maretah be'eloheiha</em> — because she has rebelled against her God. The judgment is graphic: <em>be-ḥerev yippolu</em> (they will fall by the sword), <em>ollelihem yeruttashu</em> (their infants dashed), and <em>harariotav yebukqa'u</em> (their pregnant women ripped open). These are standard ANE warfare atrocities, also invoked as covenant curses (2 Kgs 8:12; Amos 1:13). The verse closes out ch13 at maximum intensity before ch14's abrupt pivot to restoration invitation.</p>"
  },
  "14": {
    "1": "<p><span class='term'>Return, O Israel, to the LORD your God</span> — <em>shuva Yisra'el 'ad YHWH elohekha</em>: the imperative <em>shuv</em> (return, turn back) is the covenant-renewal call. The preposition is <em>'ad</em> (toward, as far as) rather than the more common <em>el</em> — a nuance suggesting completeness of return, all the way back. <em>ki kashalta ba'avonekha</em> — because you have stumbled in your iniquity. The reason given for the call is the very stumbling itself: the fall is grounds for the invitation, not disqualification from it. This pivot from 13:16's carnage to the restoration appeal is without transition — the abruptness is the point.</p>",
    "2": "<p><span class='term'>Take words with you and return</span> — <em>qeḥu immakhem devarim ve-shuvu 'el YHWH</em>. <em>Qeḥu</em> is the Qal imperative plural of <em>laqaḥ</em> (take). The instruction to bring <em>words</em> (verbal offerings, not animal sacrifices) is distinctive: this is a prayer-liturgy, not a ritual. The words prescribed follow: 'Take away all iniquity; accept what is good; and we will offer as payment the bulls of our lips.' <em>Parim sefatenu</em> — the bulls of our lips — transforms sacrifice into speech-act; lips replace the slaughtered animal. This anticipates Heb 13:15 ('a sacrifice of praise — the fruit of lips'). <em>Devarim</em> as the vehicle of return also anticipates Jer 31:33 (the word written on the heart).</p>",
    "3": "<p><span class='term'>Assyria will not save us</span> — <em>Ashshur lo' yoshi'enu</em>: the same <em>moshia'</em> root from 13:4, now applied to Assyria — with explicit denial. The three renunciations form a complete rejection of the false triad: (1) foreign military power (Assyria), (2) military hardware (<em>'al-susim lo' nirkav</em> — we will not ride on horses), and (3) idol-making (<em>ve-lo'-nomar 'od elohenu le-ma'aseh yadenu</em> — we will not again say 'our god' to the work of our hands). The renunciation of horse-warfare echoes the royal law of Deut 17:16. The idol-renunciation directly undoes the calf-kiss of 13:2. <em>Ki bekha yeruḥam yatom</em> — for in you the orphan finds mercy: the closing ground shifts from human resolution to divine compassion.</p>",
    "4": "<p><span class='term'>I will heal their waywardness</span> — <em>erpa' meshuvotam</em>: YHWH's response begins. <em>Meshuvah</em> (waywardness, apostasy, turning away) is the noun form of <em>shuv</em> — turning from YHWH. The divine commitment is to heal the very act of turning away. <em>Ahavem nedabah</em> — I will love them <em>freely/voluntarily</em>. <em>Nedabah</em> is the freewill offering (<em>nedabah</em>) of Leviticus — given without compulsion, beyond what is required, from pure generosity. Applied to divine love, it means YHWH's affection is not earned or coerced but freely bestowed. <em>Ki shav appi mimmennu</em> — for my anger has turned from them. The reversal of the anger idiom is precise: the same <em>shuv</em> Israel is called to perform (v1-2) is the word for YHWH's anger turning away.</p>",
    "5": "<p><span class='term'>I will be like dew to Israel</span> — <em>ehyeh ke-tal le-Yisra'el</em>: the botanical restoration begins. <em>Tal</em> (dew) is the critical contrast term: in 13:3, Israel's love (<em>ḥesed</em>) was 'like the early dew that goes away' — impermanent. Now YHWH's own presence is the dew — but it sustains rather than vanishes. <em>Yifrach kashoshannah</em> — he will blossom like a lily. The lily (<em>shoshannah</em>) is the flower of spring after desert heat; it also appears in Song of Songs 2:1-2 for the beloved. <em>Ve-yakh shereshav ka-Levanon</em> — he will strike root like Lebanon. Lebanon's cedars were proverbially deep-rooted; rootedness is the stability denied in the exile-imagery of previous chapters.</p>",
    "6": "<p><span class='term'>His branches will spread</span> — <em>yelekhु yonekotav</em>: the shoot-imagery (young branches, suckers) of an olive or vine. <em>Ve-yhi ke-zayit hodo</em> — his splendor will be like the olive tree. The olive was Israel's prestige crop: long-lived, perennial, the source of oil for food, light, and anointing. <em>Ve-reyḥo lo ka-Levanon</em> — his fragrance like Lebanon. Lebanon's famous cedar fragrance (resinous, durable) is now applied to restored Israel — the tree that was stripped and scattered will bear the scent of permanence. The fragrance of Lebanon appears also in Song of Songs 4:11.</p>",
    "7": "<p><span class='term'>Those who dwell in his shade will return</span> — <em>yashovu yoshevei be-tsillo</em>: <em>shuv</em> appears again — the root-word of the entire chapter. Those who shelter under the restored Israel-tree will themselves return. <em>Yeḥayu dagan</em> — they will grow grain. <em>Ve-yifsetu ka-gafen zikro</em> — his memory/fame will blossom like a vine. <em>Zikro</em> (his remembrance) — the renown of restored Israel will spread like a vine in full bearing. The agricultural metaphors accumulate: lily → cedar → olive → grain → vine, a complete harvest of the land's produce, reversing the agricultural curses of the earlier chapters.</p>",
    "8": "<p><span class='term'>Ephraim, what more do I have to do with idols</span> — <em>Ephrayim mah-li 'od la-'atsabbim</em>: YHWH addresses Ephraim directly. The question is rhetorical — Ephraim now has nothing to do with idols. The verse then becomes textually complex: <em>ani 'aniti va'ashurenu</em> — most read 'I am the one who answers him and I watch over him.' <em>Aniti</em> from <em>'anah</em> (answer/respond); <em>ashurenu</em> from <em>shur</em> (look, observe). The botanical climax follows: <em>ani ke-verosh ra'anan</em> — I am like a flourishing cypress tree. YHWH compared to a specific tree (<em>verosh</em>, cypress or juniper) is unique in the Hebrew Bible; it may play against the idolatry of cutting trees for idols (Isa 44:14 uses <em>tirzah</em> and <em>erez</em>). <em>Mimmenni peryekha nimtsa'</em> — from me your fruit is found. The source of Israel's fruitfulness is YHWH himself, not the land, the Baals, or the idols.</p>",
    "9": "<p><span class='term'>Who is wise, let him understand these things</span> — <em>mi ḥakham ve-yaven 'elleh</em>: the book closes with a wisdom call, moving from prophetic oracle to sapiential reflection. <em>Navonim ve-yeda'um</em> — the discerning will know them. <em>Ki yesharim darkei YHWH</em> — for the ways of YHWH are right (<em>yashar</em>, straight, upright). The final line encapsulates the book's moral structure: <em>u-tsaddiqim yelkhu vam</em> (the righteous walk in them) vs. <em>u-pose'im yikkashlu vam</em> (the rebellious stumble in them). The same paths lead to life for one and ruin for the other. <em>Yikkashlu</em> (stumble/fall) echoes <em>kashalta</em> (you have stumbled) of 14:1, closing the book with a structural inclusio: the call to return from stumbling in v1 is answered by the observation that those who refuse the ways of YHWH will continue to stumble.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'hosea')
    merge_comm(existing, HOSEA)
    save_comm('mkt-original', 'hosea', existing)


if __name__ == '__main__':
    main()
